SELECT COUNT(*) AS total_translations
FROM translations
WHERE status = 'approved';

SELECT *
FROM translations
WHERE status = 'approved';

SELECT translator_id, AVG(word_count) AS average_word_count
FROM translation_tasks
GROUP BY translator_id;

SELECT reviewer_name 
FROM reviewers 
ORDER BY reviewer_name ASC;

SELECT reviewer_name 
FROM reviewers 
WHERE specialization = 'technical';

SELECT COUNT(*) AS num_translators
FROM translators
WHERE specialization = 'French';

SELECT * 
FROM translation_tasks 
WHERE due_date < datetime('now') AND status != 'completed';
